'use client';

import { useCallback, useEffect, useState } from 'react'

export interface User {
  id?: string
  name: string
  full_name?: string
  username?: string
  email: string
  phone?: string
  role: 'farmer' | 'retailer' | 'admin'
  location?: string
  avatar?: string
}

export interface AuthContextType {
  user: User | null
  token: string | null
  loading: boolean
  isLoading: boolean
  isAuthenticated: boolean
  login: (email: string, password: string) => Promise<void>
  logout: () => Promise<void>
  register: (userData: Partial<User> & { password: string; confirmPassword: string }) => Promise<void>
  updateProfile: (updates: Partial<User>) => Promise<void>
}

/**
 * Hook for managing authentication state
 * Provides login, logout, register, and profile update functionality
 */
export function useAuth(): AuthContextType {
  const [user, setUser] = useState<User | null>(null)
  const [token, setToken] = useState<string | null>(null)
  const [isLoading, setIsLoading] = useState(true)

  // Initialize auth state from localStorage
  useEffect(() => {
    const initializeAuth = () => {
      try {
        const storedUser = localStorage.getItem('user')
        const storedToken = localStorage.getItem('token')
        if (storedUser) {
          setUser(JSON.parse(storedUser))
        }
        if (storedToken) {
          setToken(storedToken)
        }
      } catch (error) {
        console.error('Failed to initialize auth:', error)
      } finally {
        setIsLoading(false)
      }
    }

    initializeAuth()
  }, [])

  const login = useCallback(async (email: string, password: string) => {
    setIsLoading(true)
    try {
      // Simulate API call
      await new Promise(resolve => setTimeout(resolve, 1000))

      // Validate credentials
      if (!email || !password) {
        throw new Error('Email and password are required')
      }

      if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
        throw new Error('Invalid email format')
      }

      if (password.length < 6) {
        throw new Error('Invalid password')
      }

      // Mock user data based on email
      const role = email.includes('admin') ? 'admin' : email.includes('farmer') ? 'farmer' : 'retailer'
      const userData: User = {
        id: Math.random().toString(36).substr(2, 9),
        name: email.split('@')[0],
        full_name: email.split('@')[0],
        username: email.split('@')[0],
        email,
        role,
        location: 'Addis Ababa, Ethiopia',
      }

      const mockToken = 'mock-jwt-token-' + Math.random().toString(36).substr(2, 9)

      localStorage.setItem('user', JSON.stringify(userData))
      localStorage.setItem('token', mockToken)
      setUser(userData)
      setToken(mockToken)
    } finally {
      setIsLoading(false)
    }
  }, [])

  const logout = useCallback(async () => {
    setIsLoading(true)
    try {
      // Simulate API call
      await new Promise(resolve => setTimeout(resolve, 500))

      localStorage.removeItem('user')
      localStorage.removeItem('token')
      setUser(null)
      setToken(null)
    } finally {
      setIsLoading(false)
    }
  }, [])

  const register = useCallback(
    async (userData: Partial<User> & { password: string; confirmPassword: string }) => {
      setIsLoading(true)
      try {
        // Simulate API call
        await new Promise(resolve => setTimeout(resolve, 1000))

        // Validate input
        if (!userData.name || !userData.email) {
          throw new Error('Name and email are required')
        }

        if (userData.password !== userData.confirmPassword) {
          throw new Error('Passwords do not match')
        }

        if (userData.password && userData.password.length < 6) {
          throw new Error('Password must be at least 6 characters')
        }

        // Create user object
        const newUser: User = {
          id: Math.random().toString(36).substr(2, 9),
          name: userData.name,
          full_name: userData.name,
          username: userData.name.toLowerCase().replace(/\s+/g, '_'),
          email: userData.email,
          phone: userData.phone,
          role: userData.role || 'farmer',
          location: userData.location,
        }

        const mockToken = 'mock-jwt-token-' + Math.random().toString(36).substr(2, 9)

        localStorage.setItem('user', JSON.stringify(newUser))
        localStorage.setItem('token', mockToken)
        setUser(newUser)
        setToken(mockToken)
      } finally {
        setIsLoading(false)
      }
    },
    []
  )

  const updateProfile = useCallback(async (updates: Partial<User>) => {
    setIsLoading(true)
    try {
      // Simulate API call
      await new Promise(resolve => setTimeout(resolve, 800))

      if (!user) {
        throw new Error('User not authenticated')
      }

      const updatedUser = { ...user, ...updates }
      localStorage.setItem('user', JSON.stringify(updatedUser))
      setUser(updatedUser)
    } finally {
      setIsLoading(false)
    }
  }, [user])

  return {
    user,
    token,
    loading: isLoading,
    isLoading,
    isAuthenticated: !!user,
    login,
    logout,
    register,
    updateProfile,
  }
}
